import json

# Load 2015 metadata
with open('file_storage/functions.query_db:14.json', 'r') as f:
    metadata = json.load(f)

# Get article IDs to regions mapping
articleid_to_region = {int(item['article_id']): item['region'] for item in metadata}
print('__RESULT__:')
print(f'Total 2015 articles: {len(articleid_to_region)}')
print(json.dumps({
    'total_articles_2015': len(articleid_to_region),
    'sample': {k: articleid_to_region[k] for k in list(articleid_to_region.keys())[:5]}
}))

